// Get Proton Bridge credentials from ProtonPassCli or Azure Key Vault
// Priority: 1) ProtonPassCli, 2) Azure Key Vault, 3) Environment variables

const { execSync } = require('child_process');

let credentials = {
  host: process.env.PROTON_BRIDGE_HOST || 'host.docker.internal',
  imapPort: parseInt(process.env.PROTON_BRIDGE_IMAP_PORT || '1143'),
  smtpPort: parseInt(process.env.PROTON_BRIDGE_SMTP_PORT || '1025'),
  username: '',
  password: '',
  source: 'none'
};

// Try to get credentials from retrieval script (ProtonPassCli/Azure Vault)
try {
  const scriptPath = '/app/scripts/python/get_proton_bridge_credentials.py';
  const result = execSync(`python3 ${scriptPath} --account-name proton-bridge`, { encoding: 'utf-8' });
  const creds = JSON.parse(result);

  if (creds.username && creds.password) {
    credentials.username = creds.username;
    credentials.password = creds.password;
    credentials.source = creds.source || 'protonpasscli';
  }
} catch (error) {
  // Fallback to environment variables
  credentials.username = process.env.PROTON_BRIDGE_USERNAME || '';
  credentials.password = process.env.PROTON_BRIDGE_PASSWORD || '';
  credentials.source = 'environment';
}

return [{ json: credentials }];

// Process and format emails for MailStation
const items = $input.all();
const processed = items.map(item => {
  const email = item.json;
  return {
    from: email.from || email.fromEmail || '',
    to: 'mlesn@<LOCAL_HOSTNAME>',
    subject: email.subject || `ProtonMail: ${email.messageId || 'No Subject'}`,
    text: email.text || email.textPlain || '',
    html: email.html || email.textHtml || '',
    attachments: email.attachments || [],
    date: email.date || new Date().toISOString(),
    messageId: email.messageId || '',
    source: 'protonmail_bridge'
  };
});

return processed.map(item => ({ json: item }));

// Log successful email processing
const email = $json;
console.log(`✅ Processed ProtonMail email: ${email.subject}`);
return [{ json: { status: 'success', email: email.subject } }];
